// Frontend/src/Register.js
// SIMPLIFIED VERSION - GOOGLE OAUTH ONLY

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import API from './api';
import './App.css';

const Register = () => {
  const [step, setStep] = useState(1); // Step 1: Registration, Step 2: OTP Verification
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    phone: '',
    language: 'English'
  });
  const [otp, setOtp] = useState('');
  const [loading, setLoading] = useState(false);
  const [userId, setUserId] = useState(null);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleRegisterSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const response = await API.post('/auth/register', formData);
      if (response.data.success) {
        setUserId(response.data.userId);
        alert(`OTP sent to ${formData.phone}. Please verify.`);
        setStep(2);
      }
    } catch (error) {
      console.error('Registration error:', error.response?.data);
      alert(error.response?.data?.message || 'Registration failed.');
    } finally {
      setLoading(false);
    }
  };

  const handleOtpSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const response = await API.post('/auth/verify-otp', {
        userId: userId,
        phone: formData.phone,
        otp: otp
      });
      
      if (response.data.success) {
        alert('Phone verified successfully! You can now login.');
        navigate('/login');
      }
    } catch (error) {
      console.error('OTP verification error:', error.response?.data);
      alert(error.response?.data?.message || 'OTP verification failed.');
    } finally {
      setLoading(false);
    }
  };

  const handleResendOtp = async () => {
    setLoading(true);
    try {
      const response = await API.post('/auth/resend-otp', {
        userId: userId,
        phone: formData.phone
      });
      if (response.data.success) {
        alert('OTP resent successfully!');
      }
    } catch (error) {
      alert('Failed to resend OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleLogin = () => {
    window.location.href = 'http://localhost:5000/api/auth/google';
  };

  return (
    <div className="auth-page">
      <div className="login-container">
        <h2>Citizen Registration</h2>
        
        {step === 1 ? (
          <>
            {/* Google Login Button */}
            <div style={styles.socialSection}>
              <p style={styles.socialText}>Sign up with</p>
              <button onClick={handleGoogleLogin} style={styles.googleBtn}>
                <span style={styles.googleIcon}>G</span>
                Continue with Google
              </button>
              
              <div style={styles.divider}>
                <hr style={styles.dividerLine} />
                <span style={styles.dividerText}>OR</span>
                <hr style={styles.dividerLine} />
              </div>
            </div>

            <form onSubmit={handleRegisterSubmit}>
              <div className="form-group">
                <label>Full Name</label>
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  placeholder="Enter your full name"
                  required
                />
              </div>
              
              <div className="form-group">
                <label>Email Address</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  placeholder="Enter your email"
                  required
                />
              </div>
              
              <div className="form-group">
                <label>Phone Number</label>
                <input
                  type="tel"
                  name="phone"
                  value={formData.phone}
                  onChange={handleChange}
                  placeholder="Enter 10-digit mobile number"
                  pattern="[0-9]{10}"
                  required
                />
                <small style={styles.helpText}>📱 OTP will be sent to this number</small>
              </div>
              
              <div className="form-group">
                <label>Password</label>
                <input
                  type="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  placeholder="Create a strong password"
                  minLength="6"
                  required
                />
              </div>
              
              <div className="form-group">
                <label>Preferred Language</label>
                <select 
                  name="language" 
                  value={formData.language}
                  onChange={handleChange}
                >
                  <option value="English">English</option>
                  <option value="Marathi">Marathi</option>
                  <option value="Hindi">Hindi</option>
                </select>
              </div>
              
              <button type="submit" className="login-btn" disabled={loading}>
                {loading ? 'Processing...' : 'Register & Send OTP'}
              </button>
            </form>
          </>
        ) : (
          <div style={styles.otpContainer}>
            <div style={styles.otpIcon}>📱</div>
            <h3 style={styles.otpTitle}>Verify Your Phone</h3>
            <p style={styles.otpText}>
              We've sent a 6-digit OTP to<br />
              <strong>{formData.phone}</strong>
            </p>
            
            <form onSubmit={handleOtpSubmit}>
              <div className="form-group">
                <label>Enter OTP</label>
                <input
                  type="text"
                  value={otp}
                  onChange={(e) => setOtp(e.target.value)}
                  placeholder="Enter 6-digit OTP"
                  maxLength="6"
                  pattern="[0-9]{6}"
                  style={styles.otpInput}
                  required
                />
              </div>
              
              <button type="submit" className="login-btn" disabled={loading}>
                {loading ? 'Verifying...' : 'Verify OTP'}
              </button>
            </form>
            
            <div style={styles.resendSection}>
              <p style={styles.resendText}>Didn't receive OTP?</p>
              <button 
                onClick={handleResendOtp} 
                style={styles.resendBtn}
                disabled={loading}
              >
                Resend OTP
              </button>
            </div>
            
            <button 
              onClick={() => setStep(1)} 
              style={styles.backBtn}
            >
              ← Change Phone Number
            </button>
          </div>
        )}
        
        <p className="auth-footer">
          Already have an account? <Link to="/login">Login here</Link>
        </p>
      </div>
    </div>
  );
};

